import { AsyncPipe } from '@angular/common';
import { Component, inject } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { combineLatest, map, tap } from 'rxjs';
import { ArtworkGridComponent } from '../../components/artwork-grid/artwork-grid.component';
import { ArtworkService } from '../../services/artwork.service';
import { LanguageService } from '../../services/language.service';
import { SeoService } from '../../services/seo.service';
import { SiteService } from '../../services/site.service';

@Component({
  selector: 'app-artworks-page',
  standalone: true,
  imports: [AsyncPipe, ArtworkGridComponent],
  templateUrl: './artworks.page.html',
  styleUrl: './artworks.page.sass'
})
export class ArtworksPage {
  private readonly artworkService = inject(ArtworkService);
  private readonly languageService = inject(LanguageService);
  private readonly siteService = inject(SiteService);
  private readonly seoService = inject(SeoService);
  private readonly route = inject(ActivatedRoute);

  protected readonly vm$ = combineLatest([
    this.siteService.getSiteConfig(),
    this.artworkService.getPaintings()
  ]).pipe(
    map(([siteConfig, artworks]) => ({
      siteConfig,
      artworks,
      language: this.languageService.getRouteLanguage(this.route.snapshot),
      heroImage: artworks[0]?.images.main.sources.large || siteConfig.seo.defaultOgImage
    })),
    tap(({ siteConfig, language }) => {
      this.seoService.applyLocalizedAlternates(
        siteConfig.domain,
        this.route.snapshot,
        undefined,
        siteConfig.defaultLanguage
      );

      this.seoService.applyPageMetadata({
        title: language === 'en' ? `Artworks | ${siteConfig.artistName}` : `Opere | ${siteConfig.artistName}`,
        description:
          language === 'en'
            ? `Selection of paintings and original artworks by ${siteConfig.artistName}.`
            : `Selezione di dipinti e opere originali di ${siteConfig.artistName}.`,
        url: `${siteConfig.domain}${this.languageService.buildLocalizedPath(language, 'artworks')}`,
        image: `${siteConfig.domain}${siteConfig.seo.defaultOgImage}`,
        siteName: siteConfig.artistName,
        language
      });
    })
  );
}
